-- GRADE_TURMA

-- MATRICULA (query para inserção automática, totalizando ~5760 registros)
WITH seq AS (
    SELECT LEVEL - 1 AS offset_periodo_letivo
    FROM dual
    CONNECT BY LEVEL <= 6),
matriculas_planejadas AS (
    SELECT a.id_aluno, t.id_turma
    FROM TURMA t
    JOIN seq ON t.id_ciclo_turma = (t.id_periodo_letivo - seq.offset_periodo_letivo)
    JOIN ALUNO a ON a.id_aluno BETWEEN
        seq.offset_periodo_letivo * 20 + 1
        AND
        (seq.offset_periodo_letivo + 1) * 20
    ORDER BY
        a.id_aluno,
        t.id_periodo_letivo,
        t.id_turma
)
SELECT
    SQ_MATRICULA.NEXTVAL,
    matriculas_planejadas.id_aluno,
    matriculas_planejadas.id_turma
FROM matriculas_planejadas;

-- AVALIACAO

-- AVALIACAO_RESULTADO (definição aleatória de notas para alunos)
SELECT
    m.id_matricula,
    av.id_avaliacao,
    -- Número aleatório entre 5.0 e 10
    (5 + ROUND((DBMS_RANDOM.VALUE + DBMS_RANDOM.VALUE) / 2 * 10) / 2)
    AS qt_nota_avaliacao_aluno
FROM AVALIACAO av
JOIN MATRICULA m ON m.id_turma = av.id_turma ;

-- REGISTRO_AULA: 15 registros de aula por GRADE_TURMA
CREATE OR REPLACE FUNCTION fn_data_inicio_periodo_letivo (
    p_id_periodo_letivo IN PERIODO_LETIVO.id_periodo_letivo%TYPE
)
RETURN DATE
IS
    v_data_inicio DATE;
BEGIN
    SELECT TO_DATE(
        '01/' ||
        CASE id_semestre_periodo_letivo
            WHEN 1 THEN '01'
            WHEN 2 THEN '07'
        END || '/' || aa_periodo_letivo,
        'DD/MM/YYYY'
    )
    INTO v_data_inicio
    FROM PERIODO_LETIVO
    WHERE id_periodo_letivo = p_id_periodo_letivo;

    RETURN v_data_inicio;
END;
/

    dt_registro_aula,
    id_grade_turma
)
WITH seq AS (
    SELECT LEVEL AS rn
    FROM DUAL
    CONNECT BY LEVEL <= 15
),
datas_inicio AS (
    SELECT
        gt.id_grade_turma,
        fn_data_inicio_periodo_letivo(t.id_periodo_letivo) AS data_inicio
    FROM GRADE_TURMA gt
    JOIN TURMA t
        ON t.id_turma = gt.id_turma
)
SELECT
    TRUNC(
        di.data_inicio
        + (seq.rn - 1) * (180 / 15)
        + DBMS_RANDOM.VALUE * (180 / 15)
    ) AS dt_registro_aula,
    di.id_grade_turma
FROM datas_inicio di
CROSS JOIN seq;

-- REGISTRO_AULA_MATRICULA - Registro de chamada
    id_matricula,
    dt_registro_aula,
    id_grade_turma,
    ic_ausente_presente
)
SELECT
    m.id_matricula,
    ra.dt_registro_aula,
    ra.id_grade_turma,
    CASE
        -- 0 = ausente quando hash < 30  (~30% de ausência)
        -- 1 = presente caso contrário   (~70% de presença)
        WHEN MOD(
            ROW_NUMBER() OVER (PARTITION BY ra.dt_registro_aula, ra.id_grade_turma ORDER BY m.id_matricula)
            * 1103515245 + 12345
        , 97) < 30
        THEN 0
        ELSE 1
    END AS ic_ausente_presente
FROM REGISTRO_AULA ra
JOIN GRADE_TURMA gt
    ON gt.id_grade_turma = ra.id_grade_turma
JOIN MATRICULA m
    ON m.id_turma = gt.id_turma;
